// ToastMoleculeView.tsx — JONA View (render puro)
import React from 'react';
import { cn } from '../../lib/cn';
import { InterToastMolecule, ToastVariant } from './InterToastMolecule';
import { JPanel } from '../../atoms/JPanel/JPanel';
import { TextAtom } from '../../atoms/TextAtom/TextAtom';

const variantClasses: Record<ToastVariant, string> = {
  default: 'bg-neutral-900 text-white',
  success: 'bg-success-600 text-white',
  warning: 'bg-warning-500 text-white',
  danger:  'bg-danger-500 text-white',
};

interface ToastMoleculeViewProps extends Omit<InterToastMolecule, 'className'> {
  className?: string;
  onDismissClick?: () => void;
}

export const ToastMoleculeView: React.FC<ToastMoleculeViewProps> = ({
  message, title, variant = 'default', className, onDismissClick,
}) => (
  <JPanel variant="ghost" padding="none" radius="none"
    role="status"
    aria-live="polite"
    className={cn(
      'flex w-full min-w-0 max-w-sm items-start gap-3 rounded-md px-4 py-3 shadow-lg sm:min-w-[240px]',
      variantClasses[variant],
      className
    )}
  >
    <JPanel variant="ghost" padding="none" radius="none" className="flex-1 min-w-0">
      {title && (
        <TextAtom as="span" className="block text-sm font-semibold leading-none mb-1 break-words">
          {title}
        </TextAtom>
      )}
      <TextAtom as="span" className="block text-sm leading-snug break-words">
        {message}
      </TextAtom>
    </JPanel>
    <button
      type="button"
      aria-label="Dismiss notification"
      onClick={onDismissClick}
      className="shrink-0 opacity-70 hover:opacity-100 transition-opacity cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-white rounded"
    >
      <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
        <line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" />
      </svg>
    </button>
  </JPanel>
);
